def gen(rng, size):
    n = max(1, size)
    vals = sorted(rng.sample(range(-10000, 10001), min(n, 20001)))
    k = rng.randrange(len(vals))
    rot = vals[k:] + vals[:k]
    if rng.random() < 0.5 and vals:
        target = rng.choice(vals)
    else:
        target = rng.randint(-10001, 10001)
    return [rot, target]

